#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_initial_state() {
        let sm = UserPermissionStateMachine::new();
        assert_eq!(sm.current_state(), UserPermissionState::Active);
        assert!(sm.current_state().is_initial());
    }

    #[test]
    fn test_valid_transition() {
        let mut sm = UserPermissionStateMachine::from_state(UserPermissionState::Active);
        assert!(sm.can_transition(UserPermissionTransition::Revoke));
        let result = sm.transition(UserPermissionTransition::Revoke);
        assert!(result.is_ok());
        assert_eq!(sm.current_state(), UserPermissionState::Revoked);
    }

    #[test]
    fn test_invalid_transition() {
        let mut sm = UserPermissionStateMachine::from_state(UserPermissionState::Revoked);
        // Revoke is not valid from Revoked state
        let result = sm.transition(UserPermissionTransition::Revoke);
        assert!(result.is_err());
    }

    #[test]
    fn test_state_parsing() {
        let state: UserPermissionState = "active".parse().unwrap();
        assert_eq!(state, UserPermissionState::Active);
    }

    #[test]
    fn test_available_transitions() {
        let sm = UserPermissionStateMachine::new();
        let available = sm.available_transitions();
        // Should have at least some transitions available from initial state
        assert!(!available.is_empty() || sm.current_state().is_final());
    }
}
